import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const cores = {
  NOVO: '#1976d2',      // Azul
  ATIVO: '#388e3c',    // Verde
  CORRIGIR: '#fbc02d', // Amarelo
  SUSPENSO: '#d32f2f'  // Vermelho
};

const nomes = {
  NOVO: 'Novos',
  ATIVO: 'Ativos',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspensos'
};

function agruparPorStatus(clientes) {
  return clientes.reduce((acc, cliente) => {
    acc[cliente.status] = acc[cliente.status] || [];
    acc[cliente.status].push(cliente);
    return acc;
  }, {});
}

const ListaClientes = ({ atualizar, consultoriaFiltro, pesquisa }) => {
  const [clientes, setClientes] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchClientes = async () => {
    setLoading(true);
    const resp = await fetch('http://localhost:5000/api/clientes');
    const data = await resp.json();
    setClientes(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchClientes();
    // eslint-disable-next-line
  }, [atualizar]);

  const handleStatus = async (id, status) => {
    await fetch(`http://localhost:5000/api/clientes/${id}/status`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status })
    });
    fetchClientes();
  };

  const handleExcluir = async (id) => {
    if(window.confirm('Tem certeza que deseja excluir este cliente?')) {
      await fetch(`http://localhost:5000/api/clientes/${id}`, {
        method: 'DELETE'
      });
      fetchClientes();
    }
  };

  if (loading) return <p>Carregando clientes...</p>;
  // Filtrar por consultoria se filtro estiver ativo
  let clientesFiltrados = consultoriaFiltro
    ? clientes.filter(c => c.consultoria === consultoriaFiltro)
    : clientes;
  // Função para remover acentuação
    function removerAcentos(str) {
      return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  }
  // Filtrar por pesquisa (CNPJ ou Razão Social)
  if (pesquisa && pesquisa.trim() !== '') {
    const termo = pesquisa.trim();
    const termoNumeros = termo.replace(/\D/g, '');
    const termoTexto = removerAcentos(termo.toLowerCase());
    clientesFiltrados = clientesFiltrados.filter(c => {
      const cnpjNumeros = (c.cnpj || '').replace(/\D/g, '');
      const razao = removerAcentos((c.razaoSocial || '').toLowerCase());
      return (termoNumeros && cnpjNumeros.includes(termoNumeros)) || (termoTexto && razao.includes(termoTexto));
    });
  }
  const agrupados = agruparPorStatus(clientesFiltrados);

  return (
    <div>
      {['NOVO','ATIVO','CORRIGIR','SUSPENSO'].map(status => (
        <div key={status} style={{marginBottom:'2rem'}}>
          <h3 style={{color:cores[status]}}>{nomes[status]}</h3>
          {(agrupados[status]||[]).length === 0 && <p style={{color:'#888'}}>Nenhum cliente.</p>}
          {(agrupados[status]||[]).map(cliente => {
            const [submenuAberto, setSubmenuAberto] = useState(false);
            return (
              <div key={cliente.id} style={{background:cores[status],color:'#fff',padding:'1rem',borderRadius:'6px',marginBottom:'0.5rem',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                <div>
                  <strong>{cliente.cnpj} - {cliente.razaoSocial}</strong><br/>
                  <span>Consultoria: {cliente.consultoria}</span>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:'0.5rem'}}>
                  <div style={{display:'flex',alignItems:'center',gap:'0.3rem',position:'relative'}}>
                    <select value={cliente.status} onChange={e=>handleStatus(cliente.id, e.target.value)} style={{marginRight:'0.3rem', borderRadius: '4px', border: 'none', padding: '0.3rem 1rem', background: '#fff', color: cores[status], fontWeight: 'bold'}}>
                      <option value="NOVO">Novo</option>
                      <option value="ATIVO">Ativo</option>
                      <option value="CORRIGIR">Corrigir</option>
                      <option value="SUSPENSO">Suspenso</option>
                    </select>
                    <button onClick={()=>setSubmenuAberto(v=>!v)} title="Mais opções" style={{background:'#fff',color:cores[status],border:'none',borderRadius:'4px',padding:'0.3rem 0.7rem',fontWeight:'bold',cursor:'pointer',fontSize: '1rem',display:'flex',alignItems:'center',justifyContent:'center'}}>
                      {submenuAberto ? '▲' : '▼'}
                    </button>
                    {submenuAberto && (
                      <div style={{position:'absolute',top:'110%',right:0,background:'#fff',color:cores[status],boxShadow:'0 2px 8px rgba(0,0,0,0.15)',borderRadius:4,zIndex:10,minWidth:100}}>
                        <button onClick={()=>{setSubmenuAberto(false);handleExcluir(cliente.id);}} style={{width:'100%',background:'none',border:'none',color:cores[status],padding:'0.5rem 1rem',textAlign:'left',cursor:'pointer'}}>🗑 Excluir</button>
                      </div>
                    )}
                  </div>
                  <Link to={`/cliente/${cliente.id}`} style={{background:'#fff',color:cores[status],padding:'0.3rem 1rem',borderRadius:'4px',textDecoration:'none',fontWeight:'bold'}}>Detalhes</Link>
                </div>
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
};

export default ListaClientes;
